import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        String userInput = request.getParameter("input");

        out.println("<html>");
        out.println("<head><title>XSS Fixed Page</title></head>");
        out.println("<body>");

        // Fix: Encode user input to prevent XSS
        out.println("<p>User Input: " + encodeHtml(userInput) + "</p>");

        out.println("</body>");
        out.println("</html>");
    }

    // Function to properly encode HTML entities
    private String encodeHtml(String input) {
        if (input == null) {
            return "";
        }
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#39;");

